import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../etc/passwd";

        // Define the base path to restrict file access
        String basePath = "/var/data/";

        // Sanitize user input to prevent directory traversal attacks
        String sanitizedInput = userInput.replaceAll("\\.\\.", "");

        // Construct the full file path using a secure method
        File file = new File(basePath, sanitizedInput);

        try {
            if (file.getCanonicalPath().startsWith(basePath)) { // Check if the resolved path is within the base directory
                byte[] fileData = Files.readAllBytes(file.toPath());
                System.out.println(new String(fileData));
            } else {
                System.out.println("Access denied. Path traversal detected.");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

